--
-- Name: proc_expanded_hts_joined(); Type: PROCEDURE; Schema: expanded_hts_prep; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_hts_prep.proc_expanded_hts_joined()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;

BEGIN
SELECT TIMEOFDAY() INTO start_time;

DROP TABLE IF EXISTS expanded_hts_prep.expanded_hts_joined_new;

CREATE TABLE expanded_hts_prep.expanded_hts_joined_new AS
SELECT '******' clientcode,bio.uuid, bio.datim_id,'******' firstname, '******' surname, '******' othername, 
bio.sex, bio.age, bio.dateofbirth, '******' phonenumber, bio.maritalstatus, bio.lgaofresidence, 
bio.clientaddress, bio.stateofresidence, bio.facility, bio.state,bio.lga, bio.patientid, 
bio.education, bio.occupation,codeset.datimcode, codeset.htslatitude, codeset.htslongitude, 
codeset.datevisit, codeset.firsttimevisit, codeset.numberofchildren, codeset.numberofwives, 
codeset.indexclient, codeset.prepoffered, codeset.prepaccepted, codeset.previouslytested, 
codeset.targetgroup,codeset.referredfrom, codeset.testingsetting, codeset.counselingtype, 
codeset.pregnancystatus, codeset.breastfeeding, codeset.indextype, 
codeset.ifrecencytestingoptin, codeset.recencyid, codeset.recencytesttype, 
codeset.recencytestdate,codeset.viralloadreceivedresultdate, codeset.recencyinterpretation, 
codeset.finalrecencyresult,codeset.viralloadresult,codeset.viralloadsamplecollectiondate,
codeset.viralloadconfirmationresult,codeset.viralloadconfirmationdate, codeset.assessmentcode, 
codeset.modality, codeset.syphilistestresult,codeset.hepatitisbtestresult,
codeset.hepatitisctestresult, codeset.cd4type, codeset.cd4testresult,codeset.finalhivtestresult,
codeset.dateofhivtesting, codeset.numberofcondomsgiven, codeset.numberoflubricantsgiven, 
codeset.entrypoint,cpm.lga_id
FROM expanded_hts_prep.sub_hts_joined_bio bio
LEFT JOIN expanded_hts_prep.sub_hts_joined_codeset codeset on bio.uuid=codeset.uuid 
and bio.clientCode = codeset.clientCode and bio.datim_id=codeset.datimCode
LEFT JOIN public.central_partner_mapping cpm on bio.datim_id=cpm.datim_id;

DROP TABLE IF EXISTS expanded_hts_prep.expanded_hts_joined;
ALTER TABLE expanded_hts_prep.expanded_hts_joined_new RENAME TO expanded_hts_joined;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_hts_prep.expanded_hts_prep_monitoring (table_name, start_time,end_time) 
VALUES ('expanded_hts_joined', start_time,end_time);

END
$$;


ALTER PROCEDURE expanded_hts_prep.proc_expanded_hts_joined() OWNER TO lamisplus_etl;

