--
-- Name: proc_expanded_prep_joined(); Type: PROCEDURE; Schema: expanded_hts_prep; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_hts_prep.proc_expanded_prep_joined()
    LANGUAGE plpgsql
    AS $_$
DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;

BEGIN
SELECT TIMEOFDAY() INTO start_time;

DROP TABLE IF EXISTS expanded_hts_prep.temp_ods_patient_person;
CREATE TABLE IF NOT EXISTS expanded_hts_prep.temp_ods_patient_person AS
SELECT * FROM dblink('db_link_ods',
'SELECT pp.id,pp.uuid,pp.ods_datim_id,pp.facility_id, pp.sex, pp.date_of_birth,pp.date_of_registration, 
 pp.marital_status,pp.education, pp.employment_status,pp.address,pp.archived, prepe.extra, prepe.risk_type
 FROM ods_patient_person pp
 INNER JOIN ods_prep_enrollment prepe ON prepe.person_uuid = pp.uuid AND prepe.ods_datim_id=pp.ods_datim_id')
AS sm(id bigint,uuid character varying,ods_datim_id character varying,facility_id bigint, 
	  sex character varying, date_of_birth date,date_of_registration date, 
 	  marital_status jsonb,education jsonb, employment_status jsonb,address jsonb,
	  archived integer,extra jsonb, risk_type character varying);
CREATE INDEX IF NOT EXISTS idx_iddatim_temp_ods_patient_person ON
expanded_hts_prep.temp_ods_patient_person(id,ods_datim_id);
CREATE INDEX IF NOT EXISTS idx_uuiddatim_temp_ods_patient_person ON
expanded_hts_prep.temp_ods_patient_person(uuid,ods_datim_id);
CREATE INDEX IF NOT EXISTS idx_riskdatim_temp_ods_patient_person ON
expanded_hts_prep.temp_ods_patient_person(risk_type,ods_datim_id);

DROP TABLE IF EXISTS expanded_hts_prep.temp_ods_base_organisation_unit;
CREATE TABLE IF NOT EXISTS expanded_hts_prep.temp_ods_base_organisation_unit AS
SELECT * FROM dblink('db_link_ods','SELECT id, ods_datim_id, parent_organisation_unit_id,name
			FROM ods_base_organisation_unit') AS sm(id bigint, ods_datim_id character varying, 
			parent_organisation_unit_id bigint,name character varying);
CREATE INDEX IF NOT EXISTS idx_id_temp_ods_base_organisation_unit ON
expanded_hts_prep.temp_ods_base_organisation_unit(id);

DROP TABLE IF EXISTS expanded_hts_prep.temp_ods_base_application_codeset;
CREATE TABLE IF NOT EXISTS expanded_hts_prep.temp_ods_base_application_codeset AS
SELECT * FROM dblink('db_link_ods','SELECT id, code, ods_datim_id,display
			FROM ods_base_application_codeset') 
			AS sm(id bigint,code character varying, ods_datim_id character varying,
				  display character varying);
CREATE INDEX IF NOT EXISTS idx_codedatim_temp_ods_base_application_codeset ON
expanded_hts_prep.temp_ods_base_application_codeset(code,ods_datim_id);
CREATE INDEX IF NOT EXISTS idx_code_temp_ods_base_application_codeset ON
expanded_hts_prep.temp_ods_base_application_codeset(code);

DROP TABLE IF EXISTS expanded_hts_prep.temp_ods_prep_interruption;
CREATE TABLE IF NOT EXISTS expanded_hts_prep.temp_ods_prep_interruption AS
SELECT * FROM dblink('db_link_ods',
		   'SELECT DISTINCT person_uuid,ods_datim_id,interruption_type,interruption_date,reason_stopped
		  FROM ods_prep_interruption')
		  AS sm(person_uuid character varying,ods_datim_id character varying,
				interruption_type character varying,interruption_date date,
				reason_stopped character varying);
CREATE INDEX IF NOT EXISTS idx_personuuiddatim_temp_ods_prep_interruption ON
expanded_hts_prep.temp_ods_prep_interruption(person_uuid,ods_datim_id);

DROP TABLE IF EXISTS expanded_hts_prep.temp_ods_prep_regimen;
CREATE TABLE IF NOT EXISTS expanded_hts_prep.temp_ods_prep_regimen AS
SELECT * FROM dblink('db_link_ods','SELECT id, ods_datim_id, regimen, prep_type	
		   FROM ods_prep_regimen')
		  AS sm(id bigint, ods_datim_id character varying, regimen character varying, 
				prep_type character varying);
CREATE INDEX IF NOT EXISTS idx_iddatim_temp_ods_prep_regimen ON
expanded_hts_prep.temp_ods_prep_regimen(id,ods_datim_id);

DROP TABLE IF EXISTS expanded_hts_prep.temp_ods_hiv_enrollment;
CREATE TABLE IF NOT EXISTS expanded_hts_prep.temp_ods_hiv_enrollment AS
SELECT * FROM dblink('db_link_ods','SELECT person_uuid, ods_datim_id,date_of_registration,
								date_started 
					 FROM ods_hiv_enrollment') 
			AS sm(person_uuid character varying, ods_datim_id character varying,
				  date_of_registration date,date_started date);
CREATE INDEX IF NOT EXISTS idx_personuuiddatim_temp_ods_hiv_enrollment ON
expanded_hts_prep.temp_ods_hiv_enrollment(person_uuid,ods_datim_id);
				  
DROP TABLE IF EXISTS expanded_hts_prep.expanded_prep_joined_new;
CREATE TABLE expanded_hts_prep.expanded_prep_joined_new AS
SELECT DISTINCT ON (p.uuid, p.ods_datim_id)p.uuid AS PersonUuid,
p.id, p.uuid,'******' as hospitalNumber,'******' AS surname, '******' as firstName,
he.date_of_registration AS hivEnrollmentDate,EXTRACT(YEAR from AGE(NOW(),  date_of_birth)) as age,
'******' as otherName, p.sex as sex, p.date_of_birth as dateOfBirth,
p.date_of_registration as dateOfRegistration, p.marital_status->>'display' as maritalStatus,
education->>'display' as education, p.employment_status->>'display' as occupation,
cpm.facility_name as facilityName, cpm.facility_lga as lga, cpm.facility_state as state,
p.ods_datim_id as datimId, 
CASE WHEN p.address->'address'->0->'stateId'->>0 IS NOT NULL AND p.address->'address'->0->'stateId'->>0 ~ '^[0-9]+$'
	THEN (SELECT name FROM expanded_hts_prep.temp_ods_base_organisation_unit 
	  WHERE id = CAST(NULLIF(p.address->'address'->0 ->'stateId' ->> 0,'') AS BIGINT) and ods_datim_id=p.ods_datim_id)
        ELSE NULL END as residentialState,
CASE WHEN p.address->'address'->0->'district'->>0 IS NOT NULL AND p.address->'address'->0->'district'->>0 ~ '^[0-9]+$'
	THEN (SELECT name FROM expanded_hts_prep.temp_ods_base_organisation_unit 
	WHERE id = CAST(NULLIF(p.address->'address'->0 ->'district' ->> 0,'') AS BIGINT) and ods_datim_id=p.ods_datim_id)
	ELSE NULL END as residentialLga,
'******' AS phone,r.address as address,baseline_reg.regimen AS baselineRegimen,
(select display from expanded_hts_prep.temp_ods_base_application_codeset 
	where code = baseline_reg.prep_type and ods_datim_id=p.ods_datim_id) as prepType,
(select display from expanded_hts_prep.temp_ods_base_application_codeset 
where code = baseline_pc.prep_distribution_setting and ods_datim_id=p.ods_datim_id) AS prepDistributionSetting,
baseline_bp.systolic AS baselineSystolicBP,
baseline_bp.diastolic AS baselineDiastolicBP,
baseline_pc.weight AS baselineWeight,
baseline_pc.height AS baselineHeight,
(CASE WHEN tg.display IS NOT NULL THEN tg.display 
WHEN etg.display IS NOT NULL THEN etg.display
ELSE NULL END) AS targetGroup,
baseline_pc.encounter_date AS prepCommencementDate,
baseline_urinalysis.result AS baseLineUrinalysis,
cast(baseline_urinalysis.test_date AS date) as baseLineUrinalysisDate,
baseline_creatinine.other_test_result AS baseLineCreatinine,
cast(baseline_creatinine.other_test_date as date) AS baseLineCreatinineTestDate,
baseline_alt.other_test_result AS baseLineAlt,
baseline_hbsag.other_test_result AS baseLineHbsag,
baseline_hbpcv.other_test_result AS baseLineHbPcv,
baseline_wbc.other_test_result AS baseLineWbc,
current_alt.other_test_result as currentAlt,
cast(current_alt.other_test_date as date) as currentAltDate,
current_hbsag.other_test_result as currentHbsag,
cast(current_hbsag.other_test_date as date) as currentHbsagDate,
current_hbpcv.other_test_result as currentHbpcv,
cast(current_hbpcv.other_test_date as date) as currentHbpcvDate,
current_wbc.other_test_result as currentWbc,
cast(current_wbc.other_test_date as date) as currentWbcDate,
(CASE WHEN baseline_pc.hepatitis->>'result' LIKE 'Hepatitis B%'
THEN baseline_pc.hepatitis->>'result' ELSE NULL END) AS baseLineHepatitisB,
(CASE WHEN baseline_pc.hepatitis->>'result' LIKE 'Hepatitis C%'
THEN baseline_pc.hepatitis->>'result' ELSE NULL END) AS baseLineHepatitisC,
(select display from expanded_hts_prep.temp_ods_base_application_codeset
 where code = current_pi.interruption_type and ods_datim_id=p.ods_datim_id) as InterruptionType,
current_pi.reason_stopped AS InterruptionReason,
current_pi.interruption_date AS InterruptionDate,
(CASE WHEN baseline_hiv_status.display IS NULL AND base_eli_test.base_eli_hiv_result IS NOT NULL
THEN base_eli_test.base_eli_hiv_result ELSE
REPLACE(baseline_hiv_status.display, 'HIV ', '') END) AS HIVStatusAtPrEPInitiation,
(CASE WHEN p.extra->'prep'->>'onDemandIndication' IS NOT NULL THEN p.extra->>'onDemandIndication'
WHEN riskt.display IS NOT NULL THEN riskt.display ELSE NULL END) AS indicationForPrEP,
current_reg.regimen AS currentRegimen, 
current_pc.duration AS currentDuration,
(SELECT display FROM expanded_hts_prep.temp_ods_base_application_codeset
 where code = current_reg.prep_type and ods_datim_id=p.ods_datim_id) as currentPrepType,
(select display from expanded_hts_prep.temp_ods_base_application_codeset
where code = current_pc.prep_distribution_setting and ods_datim_id=p.ods_datim_id) AS currentPrepDistributionSetting,
current_pc.encounter_date AS DateOfLastPickup,
current_pc.systolic AS currentSystolicBP,
current_pc.diastolic AS currentDiastolicBP,
current_pc.weight AS currentWeight,
current_pc.height AS currentHeight,
current_pc.urinalysis->>'result' AS currentUrinalysis,
(SELECT display from expanded_hts_prep.temp_ods_base_application_codeset
 where code = current_pc.family_planning and ods_datim_id=p.ods_datim_id) AS familyPlanning,
current_pc.date_of_family_planning AS dateOfFamilyPlanning,
CAST(current_pc.urinalysis->>'testDate' AS DATE) AS currentUrinalysisDate,
(CASE WHEN current_hiv_status.display IS NULL AND eli_hiv_result IS NOT NULL THEN eli_hiv_result
WHEN current_hiv_status.display IS NOT NULL THEN REPLACE(current_hiv_status.display, 'HIV ', '')
WHEN he.date_started IS NOT NULL THEN 'Positive' ELSE NULL
END) AS currentHivStatus,
current_pc.encounter_date AS DateOfCurrentHIVStatus,
(CASE WHEN p.sex='Male' THEN NULL
WHEN current_pc.pregnant IS NOT NULL AND current_pc.pregnant='true' 
THEN (SELECT display FROM expanded_hts_prep.temp_ods_base_application_codeset 
WHERE code = current_pc.pregnant and ods_datim_id=p.ods_datim_id)
ELSE 'Not Pregnant' END) AS pregnancyStatus,
(CASE
WHEN prepi.interruption_date  > prepc.encounter_date THEN bac.display
WHEN prepc.status IS NOT NULL THEN prepc.status
ELSE NULL END) AS CurrentStatus,
(CASE
WHEN prepi.interruption_date  > prepc.encounter_date THEN prepi.interruption_date
WHEN prepc.status IS NOT NULL THEN prepc.encounter_date
ELSE NULL END) AS DateOfCurrentStatus
FROM expanded_hts_prep.temp_ods_patient_person p
INNER JOIN expanded_hts_prep.cte_prep_bio r ON r.id=p.id AND r.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_current_pc current_pc ON current_pc.person_uuid=p.uuid AND current_pc.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_pc baseline_pc ON baseline_pc.person_uuid=p.uuid AND baseline_pc.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_bp baseline_bp ON baseline_bp.person_uuid=p.uuid AND baseline_bp.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_urinalysis baseline_urinalysis ON baseline_urinalysis.person_uuid=p.uuid AND baseline_urinalysis.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_creatinine baseline_creatinine ON baseline_creatinine.person_uuid=p.uuid AND baseline_creatinine.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_alt baseline_alt ON baseline_alt.person_uuid=p.uuid AND baseline_alt.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_hbsag baseline_hbsag ON baseline_hbsag.person_uuid=p.uuid AND baseline_hbsag.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_hbpcv baseline_hbpcv ON baseline_hbpcv.person_uuid=p.uuid AND baseline_hbpcv.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_wbc baseline_wbc ON baseline_wbc.person_uuid=p.uuid AND baseline_wbc.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_current_alt current_alt ON current_alt.person_uuid=p.uuid AND current_alt.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_current_hbsag current_hbsag ON current_hbsag.person_uuid=p.uuid AND current_hbsag.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_current_hbpcv current_hbpcv ON current_hbpcv.person_uuid=p.uuid AND current_hbpcv.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_current_wbc current_wbc ON current_wbc.person_uuid=p.uuid AND current_wbc.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_prepi prepi ON prepi.person_uuid=p.uuid AND  prepi.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_prepc prepc ON prepc.person_uuid=p.uuid AND prepc.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_eli_test eli_test ON eli_test.person_uuid=p.uuid AND eli_test.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_base_eli_test base_eli_test ON base_eli_test.person_uuid=p.uuid AND base_eli_test.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_e_target e_target ON e_target.person_uuid=p.uuid AND e_target.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_penrol penrol ON penrol.person_uuid=p.uuid AND penrol.ods_datim_id=p.ods_datim_id
LEFT JOIN public.central_partner_mapping cpm on p.ods_datim_id=cpm.datim_id
LEFT JOIN expanded_hts_prep.temp_ods_base_application_codeset riskt ON riskt.code = p.risk_type AND riskt.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.temp_ods_base_application_codeset tg ON tg.code = penrol.target_group AND tg.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.temp_ods_base_application_codeset etg ON etg.code = e_target.eli_target AND etg.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.temp_ods_prep_interruption current_pi ON current_pi.person_uuid=p.uuid AND current_pi.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.temp_ods_prep_regimen current_reg ON current_reg.id = current_pc.regimen_id 
AND current_reg.ods_datim_id=current_pc.ods_datim_id
LEFT JOIN expanded_hts_prep.temp_ods_base_application_codeset current_hiv_status ON current_hiv_status.code = current_pc.hiv_test_result
AND current_hiv_status.ods_datim_id = current_pc.ods_datim_id
LEFT JOIN expanded_hts_prep.temp_ods_prep_regimen baseline_reg ON baseline_reg.id = baseline_pc.regimen_id
AND baseline_reg.ods_datim_id = baseline_pc.ods_datim_id
LEFT JOIN expanded_hts_prep.temp_ods_base_application_codeset baseline_hiv_status ON baseline_hiv_status.code=baseline_pc.hiv_test_result 
AND baseline_hiv_status.ods_datim_id=baseline_pc.ods_datim_id
LEFT JOIN expanded_hts_prep.temp_ods_hiv_enrollment he ON he.person_uuid = p.uuid AND he.ods_datim_id = p.ods_datim_id
LEFT JOIN expanded_hts_prep.temp_ods_base_application_codeset bac ON bac.code=prepi.interruption_type
AND bac.ods_datim_id=prepi.ods_datim_id
WHERE p.archived=0 AND p.date_of_registration BETWEEN '1980-01-01' 
AND (select date from expanded_hts_prep.period where is_active);

DROP TABLE IF EXISTS expanded_hts_prep.expanded_prep_joined;
ALTER TABLE expanded_hts_prep.expanded_prep_joined_new RENAME TO expanded_prep_joined;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_hts_prep.expanded_hts_prep_monitoring (table_name, start_time,end_time) 
VALUES ('expanded_prep_joined', start_time,end_time);

DROP TABLE IF EXISTS expanded_hts_prep.temp_ods_base_organisation_unit;
DROP TABLE IF EXISTS expanded_hts_prep.temp_ods_base_application_codeset;
DROP TABLE IF EXISTS expanded_hts_prep.temp_ods_prep_interruption;
DROP TABLE IF EXISTS expanded_hts_prep.temp_ods_prep_regimen;
DROP TABLE IF EXISTS expanded_hts_prep.temp_ods_hiv_enrollment;
DROP TABLE IF EXISTS expanded_hts_prep.temp_ods_patient_person;

END
$_$;


ALTER PROCEDURE expanded_hts_prep.proc_expanded_prep_joined() OWNER TO lamisplus_etl;

--
-- Name: proc_loop_through_lists(); Type: PROCEDURE; Schema: expanded_hts_prep; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_hts_prep.proc_loop_through_lists()
    LANGUAGE plpgsql
    AS $$
DECLARE
    inputs text[];
    input text;
    partition_name text;
BEGIN
    -- Populate the array with values from the existing table
    SELECT array_agg(periodid) 
    INTO inputs
    FROM expanded_hts_prep.period;

    -- Loop through each input value and execute the dynamic query
    FOREACH input IN ARRAY inputs
    LOOP
        partition_name := CONCAT('expanded_prep_', input);
        
		EXECUTE format('
            DROP TABLE IF EXISTS expanded_hts_prep.%I 
           ', partition_name);
			
        -- Loop through and create partitions
        EXECUTE format('
            CREATE TABLE IF NOT EXISTS expanded_hts_prep.%I 
            PARTITION OF expanded_hts_prep.expanded_prep_weekly_updated
            FOR VALUES IN (%L)', partition_name, input);
    END LOOP;
END;
$$;


ALTER PROCEDURE expanded_hts_prep.proc_loop_through_lists() OWNER TO lamisplus_etl;

