pi.id, pi.interruption_date , pi.interruption_type
FROM ods_prep_interruption pi
INNER JOIN (SELECT DISTINCT pi.person_uuid, pi.ods_datim_id,MAX(pi.interruption_date)interruption_date
			FROM ods_prep_interruption pi WHERE pi.archived=0
