WHERE pi.archived=0
GROUP BY pi.ods_datim_id, pi.id, pi.person_uuid, pi.interruption_date, pi.interruption_type')
AS sm(person_uuid character varying, ods_datim_id character varying,
id bigint, interruption_date date, interruption_type character varying);

