--
-- Name: proc_sub_expanded_hts_joined_bio(); Type: PROCEDURE; Schema: expanded_hts_prep; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_hts_prep.proc_sub_expanded_hts_joined_bio()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;

BEGIN
SELECT TIMEOFDAY() INTO start_time;

DROP TABLE IF EXISTS expanded_hts_prep.temp_sub_hts_joined_bio;
CREATE TABLE IF NOT EXISTS expanded_hts_prep.temp_sub_hts_joined_bio AS
SELECT * FROM dblink('db_link_ods',
'SELECT DISTINCT ON (hc.uuid,hc.client_code,hc.ods_datim_id) hc.uuid, hc.client_code AS clientCode,  
''2024W37'' AS period,hc.person_uuid,hc.ods_datim_id as datim_id,hc.extra, 
(CASE WHEN hc.person_uuid IS NULL THEN INITCAP(hc.extra->>''gender'') ELSE INITCAP(pp.sex) END) AS sex,      
(CASE WHEN hc.person_uuid IS NULL THEN CAST(hc.extra->>''age'' AS INTEGER)        
ELSE CAST(EXTRACT(YEAR from AGE(NOW(),  pp.date_of_birth)) AS INTEGER )       
END) AS age,    
(CASE WHEN hc.person_uuid IS NOT NULL THEN pp.date_of_birth       
WHEN hc.person_uuid IS NULL AND LENGTH(hc.extra->>''date_of_birth'') > 0    
AND hc.extra->>''date_of_birth'' != '''' THEN CAST(NULLIF(hc.extra->>''date_of_birth'', '''') AS DATE)       
ELSE NULL END) AS dateOfBirth,     
(CASE WHEN hc.person_uuid IS NULL THEN hc.extra->>''marital_status''       
ELSE pp.marital_status->>''display'' END) AS maritalStatus,         
(CASE WHEN hc.person_uuid IS NULL        
THEN hc.extra->>''state_of_residence'' ELSE pp.address ->>''{address,0,city}'' END) AS StateOfResidence,      
facility.facility_name AS facility,facility.facility_state AS state,facility.facility_lga AS lga,      
pp.uuid AS patientId,
pp.education->>''display'' as education,        
pp.employment_status->>''display'' as occupation
FROM ods_hts_client hc     
LEFT JOIN ods_patient_person pp ON pp.uuid=hc.person_uuid AND pp.ods_datim_id=hc.ods_datim_id       
LEFT JOIN public.central_partner_mapping facility ON hc.ods_datim_id=facility.datim_id    
WHERE hc.archived=0 AND hc.date_visit >=''1980-01-01'' 
AND hc.date_visit <=  (select date from expanded_hts_prep.period where is_active)')
AS sm(uuid character varying,clientcode character varying,period text,person_uuid character varying,
	datim_id character varying(255),extra jsonb,sex text,age integer,dateofbirth date,
	maritalstatus text,stateofresidence text,facility character varying(255),
	state character varying(255),lga character varying(255),patientid character varying,
	 education text,occupation text);

CREATE INDEX idx_personuuiddatimid_tempsubhtsjoinedbio 
ON expanded_hts_prep.temp_sub_hts_joined_bio(person_uuid,datim_id);

drop table if exists expanded_hts_prep.sub_hts_joined_bio_new;
create table expanded_hts_prep.sub_hts_joined_bio_new as
SELECT hc.*,
(CASE WHEN hc.person_uuid IS NULL THEN hc.extra->>'client_address' ELSE r.address END) AS clientAddress,
(CASE WHEN hc.person_uuid IS NULL THEN hc.extra->>'lga_of_residence' 
 ELSE NULL
--  (SELECT name FROM dblink('db_link_ods',
-- 	'SELECT name FROM ods_base_organisation_unit') 
-- 	AS sm(name character varying)
-- 		WHERE ods_datim_id=r.ods_datim_id LIMIT 1) 
END) AS LGAOfResidence
FROM expanded_hts_prep.temp_sub_hts_joined_bio hc
LEFT JOIN expanded_hts_prep.cte_prep_bio r ON r.uuid=hc.person_uuid 
AND r.ods_datim_id=hc.datim_id;

DROP TABLE IF EXISTS expanded_hts_prep.sub_hts_joined_bio;
ALTER TABLE expanded_hts_prep.sub_hts_joined_bio_new RENAME TO sub_hts_joined_bio;

drop index if exists idx_sub_hts_joined_bio;
create index idx_sub_hts_joined_bio 
on expanded_hts_prep.sub_hts_joined_bio (clientCode,datim_id,uuid); 

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_hts_prep.expanded_hts_prep_monitoring (table_name, start_time,end_time) 
VALUES ('sub_hts_joined_bio', start_time,end_time);

DROP TABLE IF EXISTS expanded_hts_prep.temp_sub_hts_joined_bio;

END
$$;


