              set is_active = true 
              where periodid in (''2024W42'')
              --date = current_date-7
			 '));
			 
update expanded_hts_prep.period 
set is_active = false;

update expanded_hts_prep.period 
set is_active = true 
where periodid in ('2024W42');
--where date = current_date-7;

INSERT INTO expanded_hts_prep.expanded_hts_prep_monitoring (table_name, start_time) 
VALUES ('period', start_time);

END
$$;


