--
-- Name: proc_upsert_hts_client_codeset_refresh(); Type: PROCEDURE; Schema: expanded_hts_prep; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_hts_prep.proc_upsert_hts_client_codeset_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN
-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'hts_client_codeset_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE FORMAT(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(uuid) 
	 FROM ods_hts_client 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

-- DROP TABLE IF EXISTS expanded_hts_prep.hts_client_codeset_refresh;
CREATE TABLE IF NOT EXISTS expanded_hts_prep.hts_client_codeset_refresh
(	clientcode character varying,uuid character varying,datimcode character varying(255),
    htslatitude text,htslongitude text, datevisit date,firsttimevisit text,
    numberofchildren integer,numberofwives integer,indexclient text,
    prepoffered text,prepaccepted text,previouslytested text,targetgroup character varying,
    referredfrom character varying,testingsetting character varying,
    counselingtype character varying,pregnancystatus character varying,
    breastfeeding text,indextype character varying,ifrecencytestingoptin text,
    recencyid text,recencytesttype text,recencytestdate date,viralloadreceivedresultdate date,
    recencyinterpretation text,finalrecencyresult text,viralloadresult text,
    viralloadsamplecollectiondate date,viralloadconfirmationresult text,
    viralloadconfirmationdate date,assessmentcode character varying,
    modality character varying,syphilistestresult text,hepatitisbtestresult text,
    hepatitisctestresult text,cd4type text,cd4testresult text,finalhivtestresult text,
    dateofhivtesting date,numberofcondomsgiven character varying,numberoflubricantsgiven character varying,
    entrypoint character varying,
 	CONSTRAINT unq_persondatimcodeuuid_htsclientbascodeapprefresh
	UNIQUE (clientcode,datimcode,uuid)
);

CREATE INDEX IF NOT EXISTS idx_clientcodedatimcodedatevisit_htsclientbasecodeapprefresh ON 
expanded_hts_prep.hts_client_codeset_refresh(clientcode,datimcode,datevisit);

SELECT TIMEOFDAY() INTO start_time;

EXECUTE FORMAT('INSERT INTO expanded_hts_prep.hts_client_codeset_refresh
SELECT * FROM dblink(''db_link_ods'',
''
SELECT DISTINCT ON (hc.client_code, hc.ods_datim_id) hc.client_code AS clientCode,  
hc.uuid,
hc.ods_datim_id as datimCode,       
hc.others->>''''latitude'''' AS HTSLatitude,       
hc.others->>''''longitude'''' AS HTSLongitude,        
hc.date_visit AS dateVisit,       
(CASE WHEN hc.first_time_visit IS true THEN ''''Yes'''' ELSE ''''No'''' END) firstTimeVisit,       
hc.num_children AS numberOfChildren,       
hc.num_wives AS numberOfWives,       
(CASE WHEN hc.index_client IS true THEN ''''Yes'''' ELSE ''''No'''' END) indexClient,       
(CASE WHEN hc.hiv_test_result = ''''Positive'''' THEN ''''No''''  
WHEN hc.prep_offered IS true THEN ''''Yes'''' ELSE ''''No'''' END)  AS prepOffered,       
(CASE WHEN hc.hiv_test_result = ''''Positive'''' THEN ''''No''''  
WHEN hc.prep_accepted IS true THEN ''''Yes'''' ELSE ''''No'''' END) AS prepAccepted,       
(CASE WHEN hc.previously_tested IS true THEN ''''Yes'''' ELSE ''''No'''' END) AS previouslyTested,       
tg.display AS targetGroup,       
rf.display AS referredFrom,       
ts.display AS testingSetting,       
tc.display AS counselingType,       
preg.display AS pregnancyStatus,       
(CASE   
WHEN preg.display=''''Breastfeeding'''' THEN ''''Yes''''    
WHEN preg.display IS NULL THEN NULL   
ELSE ''''No''''   
END) AS breastFeeding,  
it.display AS indexType,       
(CASE WHEN hc.recency->>''''optOutRTRI'''' ILIKE ''''true'''' THEN ''''Yes''''     
WHEN hc.recency->>''''optOutRTRI'''' ILIKE ''''false'''' THEN ''''No''''    
WHEN hc.recency->>''''optOutRTRI'''' != NULL THEN hc.recency->>''''optOutRTRI''''   
ELSE NULL END) AS IfRecencyTestingOptIn,       
hc.recency->>''''rencencyId'''' AS RecencyID,       
hc.recency->>''''optOutRTRITestName'''' AS recencyTestType,       
(CASE WHEN hc.recency->>''''optOutRTRITestDate'''' IS NOT NULL      
AND hc.recency->>''''optOutRTRITestDate'''' != '''''''' AND LENGTH(hc.recency->>''''optOutRTRITestDate'''') > 0      
THEN CAST(NULLIF(hc.recency->>''''optOutRTRITestDate'''', '''''''') AS DATE)     
WHEN hc.recency->>''''sampleTestDate'''' IS NOT NULL      
AND hc.recency->>''''sampleTestDate'''' != '''''''' AND LENGTH(hc.recency->>''''sampleTestDate'''') > 0   
THEN CAST(NULLIF(hc.recency->>''''sampleTestDate'''', '''''''') AS DATE) ELSE NULL END) AS recencyTestDate,      
(CASE WHEN hc.recency->>''''receivedResultDate'''' IS NOT NULL      
AND hc.recency->>''''receivedResultDate'''' != '''''''' AND LENGTH(hc.recency->>''''receivedResultDate'''') > 0  
THEN CAST(NULLIF(hc.recency->>''''receivedResultDate'''', '''''''') AS DATE) ELSE NULL END) AS viralLoadReceivedResultDate,
(CASE      
WHEN hc.recency->>''''rencencyInterpretation'''' IS NOT NULL      
AND hc.recency->>''''rencencyInterpretation'''' ILIKE ''''%%Long%%'''' THEN ''''RTRI Longterm''''    
WHEN hc.recency->>''''rencencyInterpretation'''' IS NOT NULL      
AND hc.recency->>''''rencencyInterpretation'''' ILIKE ''''%%Recent%%'''' THEN ''''RTRI Recent''''     
ELSE hc.recency->>''''rencencyInterpretation'''' END) AS recencyInterpretation,      
hc.recency->>''''finalRecencyResult'''' AS finalRecencyResult,       
hc.recency->>''''viralLoadResultClassification'''' AS viralLoadResult,      
CAST(NULLIF(hc.recency->>''''sampleCollectedDate'''', '''''''') AS DATE) AS viralLoadSampleCollectionDate,    
hc.recency->>''''viralLoadConfirmationResult'''' AS viralLoadConfirmationResult,     
CAST(NULLIF(hc.recency->>''''viralLoadConfirmationTestDate'''', '''''''') AS DATE) AS viralLoadConfirmationDate,      
hc.risk_stratification_code AS Assessmentcode,       
modality_code.display AS modality,       
(CASE WHEN hc.syphilis_testing->>''''syphilisTestResult'''' ILIKE ''''Yes''''        
THEN ''''Reactive'''' ELSE ''''Non-Reactive'''' END) As syphilisTestResult,       
(CASE WHEN hc.hepatitis_testing->>''''hepatitisBTestResult'''' ILIKE ''''Yes''''        
THEN ''''Positive'''' ELSE ''''Negative'''' END) AS hepatitisBTestResult,       
(CASE WHEN hc.hepatitis_testing->>''''hepatitisCTestResult'''' ILIKE ''''Yes''''        
THEN ''''Positive'''' ELSE ''''Negative'''' END) AS hepatitisCTestResult,       
hc.cd4->>''''cd4Count'''' AS CD4Type,       
hc.cd4->>''''cd4SemiQuantitative'''' AS CD4TestResult,       
(CASE WHEN hc.hiv_test_result2 = ''''Positive'''' THEN ''''Positive''''  
WHEN  hc.hiv_test_result =''''Negative'''' THEN ''''Negative''''  
WHEN  hc.hiv_test_result =''''Positive'''' AND hc.hiv_test_result2=''''Negative'''' THEN ''''Negative''''  
WHEN  hc.hiv_test_result =''''Positive'''' AND hc.hiv_test_result2 IS NULL THEN ''''Positive''''  
WHEN hc.test1->>''''result'''' ILIKE ''''Yes'''' THEN ''''Positive'''' ELSE ''''Negative'''' END) AS finalHIVTestResult,      
(CASE WHEN LENGTH(hc.test1->>''''date'''') > 0 AND hc.test1->>''''date'''' !=''''''''    
THEN CAST(NULLIF(hc.test1->>''''date'''', '''''''') AS DATE)       
WHEN hc.date_visit IS NOT NULL THEN hc.date_visit        
ELSE NULL END)dateOfHIVTesting,       
CAST(post_test_counseling->>''''condomProvidedToClientCount'''' AS VARCHAR) AS numberOfCondomsGiven,      
CAST(post_test_counseling->>''''lubricantProvidedToClientCount'''' AS VARCHAR) AS numberOfLubricantsGiven,
entry.display as entrypoint
FROM (SELECT client_code,ods_datim_id,uuid,others,first_time_visit,num_children,num_wives,
index_client,hiv_test_result,prep_offered,prep_accepted, previously_tested,testing_setting,
recency, syphilis_testing hepatitis_testing,cd4, hiv_test_result2, test1, date_visit,type_counseling,
pregnant,risk_stratification_code, target_group,relation_with_index_client, referred_from,
syphilis_testing,post_test_counseling,archived
FROM ods_hts_client WHERE ods_load_time >= ''%L'') hc     
LEFT JOIN ods_hts_risk_stratification hrs ON hrs.code = hc.risk_stratification_code AND hrs.ods_datim_id=hc.ods_datim_id
LEFT JOIN ods_base_application_codeset entry ON entry.code = hrs.entry_point AND entry.ods_datim_id=hrs.ods_datim_id
LEFT JOIN ods_base_application_codeset tg ON tg.code = hc.target_group AND tg.ods_datim_id = hc.ods_datim_id       
LEFT JOIN ods_base_application_codeset it ON it.id = hc.relation_with_index_client AND it.ods_datim_id = hc.ods_datim_id
LEFT JOIN ods_base_application_codeset rf ON rf.id = hc.referred_from AND rf.ods_datim_id = hc.ods_datim_id   
LEFT JOIN ods_base_application_codeset ts ON ts.code = hc.testing_setting AND ts.ods_datim_id = hc.ods_datim_id       
LEFT JOIN ods_base_application_codeset tc ON tc.id = hc.type_counseling  AND  tc.ods_datim_id = hc.ods_datim_id
LEFT JOIN ods_base_application_codeset preg ON preg.id = hc.pregnant AND preg.ods_datim_id = hc.ods_datim_id       
LEFT JOIN ods_base_application_codeset relation ON relation.id = hc.relation_with_index_client AND relation.ods_datim_id = hc.ods_datim_id           
LEFT JOIN ods_base_application_codeset modality_code ON modality_code.code = hrs.modality AND modality_code.ods_datim_id = hrs.ods_datim_id       
WHERE hc.archived=0
'')
AS sm(clientcode character varying,uuid character varying,datimcode character varying(255),htslatitude text,htslongitude text,
    datevisit date,firsttimevisit text,numberofchildren integer,numberofwives integer,indexclient text,prepoffered text,
    prepaccepted text,previouslytested text,targetgroup character varying,referredfrom character varying,
    testingsetting character varying,counselingtype character varying,pregnancystatus character varying,
    breastfeeding text,indextype character varying,ifrecencytestingoptin text,recencyid text,recencytesttype text,
    recencytestdate date,viralloadreceivedresultdate date,recencyinterpretation text,finalrecencyresult text,
    viralloadresult text,viralloadsamplecollectiondate date,viralloadconfirmationresult text,viralloadconfirmationdate date,
    assessmentcode character varying,modality character varying,syphilistestresult text,hepatitisbtestresult text,
    hepatitisctestresult text,cd4type text,cd4testresult text,finalhivtestresult text,dateofhivtesting date,
    numberofcondomsgiven character varying,numberoflubricantsgiven character varying,entrypoint character varying)
ON CONFLICT(clientcode,datimcode,uuid)
DO UPDATE SET
datevisit=EXCLUDED.datevisit, numberofchildren=EXCLUDED.numberofchildren,
numberofwives=EXCLUDED.numberofwives, indexclient=EXCLUDED.indexclient,
prepoffered=EXCLUDED.prepoffered, prepaccepted=EXCLUDED.prepaccepted,
previouslytested=EXCLUDED.previouslytested, targetgroup=EXCLUDED.targetgroup,
referredfrom=EXCLUDED.referredfrom, testingsetting=EXCLUDED.testingsetting,
counselingtype=EXCLUDED.counselingtype, pregnancystatus=EXCLUDED.pregnancystatus,
breastfeeding=EXCLUDED.breastfeeding, indextype=EXCLUDED.indextype,
ifrecencytestingoptin=EXCLUDED.ifrecencytestingoptin, recencytesttype=EXCLUDED.recencytesttype,
recencytestdate=EXCLUDED.recencytestdate, viralloadreceivedresultdate=EXCLUDED.viralloadreceivedresultdate,
recencyinterpretation=EXCLUDED.recencyinterpretation,finalrecencyresult=EXCLUDED.finalrecencyresult,
viralloadresult=EXCLUDED.viralloadresult, viralloadsamplecollectiondate=EXCLUDED.viralloadsamplecollectiondate,
assessmentcode=EXCLUDED.assessmentcode,modality=EXCLUDED.modality,syphilistestresult=EXCLUDED.syphilistestresult,
hepatitisbtestresult=EXCLUDED.hepatitisbtestresult,hepatitisctestresult=EXCLUDED.hepatitisctestresult,
cd4type=EXCLUDED.cd4type,cd4testresult=EXCLUDED.cd4testresult,finalhivtestresult=EXCLUDED.finalhivtestresult,
dateofhivtesting=EXCLUDED.dateofhivtesting,numberofcondomsgiven=EXCLUDED.numberofcondomsgiven,
numberoflubricantsgiven=EXCLUDED.numberoflubricantsgiven, entrypoint=EXCLUDED.entrypoint',last_load_end_time);

SELECT TIMEOFDAY() INTO end_time;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('hts_client_codeset_refresh',start_time, end_time,record_count);
		 
END 
$$;


ALTER PROCEDURE expanded_hts_prep.proc_upsert_hts_client_codeset_refresh() OWNER TO lamisplus_etl;

--
-- Name: proc_upsert_hts_client_refresh(); Type: PROCEDURE; Schema: expanded_hts_prep; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_hts_prep.proc_upsert_hts_client_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN
-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'hts_client_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE FORMAT(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(uuid) 
	 FROM ods_hts_client 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

CREATE TABLE IF NOT EXISTS expanded_hts_prep.hts_client_refresh
(	uuid character varying,client_code character varying,
 person_uuid character varying,ods_datim_id character varying,
	extra jsonb,date_visit date,archived integer,facility character varying,
		state character varying, lga character varying,
	CONSTRAINT unq_uuidpersondatim_htsclientrefresh
	UNIQUE (uuid,person_uuid,ods_datim_id,extra)
);

CREATE INDEX IF NOT EXISTS idx_personuuiddatimdatevisit_htsclientrefresh ON 
expanded_hts_prep.hts_client_refresh(date_visit,person_uuid,ods_datim_id);

SELECT TIMEOFDAY() INTO start_time;

EXECUTE FORMAT('INSERT INTO expanded_hts_prep.hts_client_refresh
SELECT * FROM dblink(''db_link_ods'',
''SELECT DISTINCT ON (hc.uuid,hc.person_uuid,hc.ods_datim_id) hc.uuid,''''******'''' client_code,
		hc.person_uuid,hc.ods_datim_id,hc.extra,hc.date_visit,
        hc.archived,facility.facility_name AS facility,facility.facility_state AS state,
        facility.facility_lga AS lga
 FROM (SELECT uuid,person_uuid,ods_datim_id,extra,date_visit,archived
       FROM ods_hts_client WHERE ods_load_time > ''%L'' AND archived = 0) AS hc
 LEFT JOIN public.central_partner_mapping AS facility ON hc.ods_datim_id = facility.datim_id
'')AS sm(uuid character varying,client_code character varying,person_uuid character varying,ods_datim_id character varying,
		extra jsonb,date_visit date,archived integer,facility character varying,
		state character varying, lga character varying)
ON CONFLICT(uuid,person_uuid,ods_datim_id,extra)
DO UPDATE SET
	date_visit=EXCLUDED.date_visit',last_load_end_time);

UPDATE expanded_hts_prep.hts_client_refresh
SET client_code='******' WHERE client_code!='******';

SELECT TIMEOFDAY() INTO end_time;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('hts_client_refresh',start_time, end_time,record_count);
		 
END 
$$;


