--
-- Name: proc_loop_through_lists(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_loop_through_lists()
    LANGUAGE plpgsql
    AS $$
DECLARE
    inputs text[];
    input text;
    partition_name text;
BEGIN
    -- Populate the array with values from the existing table
    SELECT array_agg(periodcode) 
    INTO inputs
    FROM public.period;

    -- Loop through each input value and execute the dynamic query
    FOREACH input IN ARRAY inputs
    LOOP
        partition_name := CONCAT('flatfile_hts_', input);
        
		EXECUTE format('
            DROP TABLE IF EXISTS public.%I 
           ', partition_name);
			
        -- Loop through and create partitions
        EXECUTE format('
            CREATE TABLE IF NOT EXISTS public.%I 
            PARTITION OF public.aggregate_flatfile_hts_backup
            FOR VALUES IN (%L)', partition_name, input);
    END LOOP;
END;
$$;


ALTER PROCEDURE public.proc_loop_through_lists() OWNER TO lamisplus_etl;

--
-- Name: proc_stream_aggregate_flatfile_hts(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_stream_aggregate_flatfile_hts()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;

BEGIN

SELECT TIMEOFDAY() INTO start_time;

INSERT INTO public.aggregate_flatfile_hts_backup
SELECT * FROM public.aggregate_flatfile_hts;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO public.hts_prep_monitoring(table_name, start_time,end_time) 
VALUES ('aggregate_flatfile_hts', start_time,end_time);
		 
END 
