--
-- Name: proc_stream_hts(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_stream_hts()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;

BEGIN

SELECT TIMEOFDAY() INTO start_time;

INSERT INTO public.final_hts
SELECT period, clientcode, datim_id, firstname, surname, othername, sex, 
age, dateofbirth, phonenumber, maritalstatus, lgaofresidence, stateofresidence, 
facility, state, lga, patientid, education, occupation, datimcode, htslatitude,
htslongitude, clientaddress, datevisit, firsttimevisit, numberofchildren, 
numberofwives, indexclient, prepoffered, prepaccepted, previouslytested, targetgroup, 
referredfrom, testingsetting, counselingtype, pregnancystatus, breastfeeding, indextype, 
ifrecencytestingoptin, recencyid, recencytesttype, recencytestdate, viralloadreceivedresultdate, 
recencyinterpretation, finalrecencyresult, viralloadresult, viralloadsamplecollectiondate, 
viralloadconfirmationresult, viralloadconfirmationdate, assessmentcode, modality, 
syphilistestresult, hepatitisbtestresult, hepatitisctestresult, cd4type, cd4testresult, 
finalhivtestresult, dateofhivtesting, numberofcondomsgiven, numberoflubricantsgiven, 
period_start_date, period_end_date, entrypoint, lga_id
FROM expanded_hts_prep.expanded_hts_weekly
WHERE period ILIKE '2024W%';

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO public.hts_prep_monitoring(table_name, start_time,end_time) 
VALUES ('final_hts', start_time,end_time);
		 
END 
$$;


ALTER PROCEDURE public.proc_stream_hts() OWNER TO lamisplus_etl;

