BEGIN

SELECT TIMEOFDAY() INTO start_time;

INSERT INTO public.final_prep
SELECT period, personuuid, id, uuid, hospitalnumber, surname, firstname, 
hivenrollmentdate, age, othername, sex, dateofbirth, dateofregistration, 
maritalstatus, education, occupation, facilityname, lga, state, datimid, 
residentialstate, residentiallga, phone, address, baselineregimen, preptype, 
prepdistributionsetting, baselinesystolicbp, baselinediastolicbp, baselineweight,
baselineheight, targetgroup, prepcommencementdate, baselineurinalysis, 
baselineurinalysisdate, baselinecreatinine, baselinecreatininetestdate, baselinealt, 
baselinehbsag, baselinehbpcv, baselinewbc, currentalt, currentaltdate, currenthbsag,
currenthbsagdate, currenthbpcv, currenthbpcvdate, currentwbc, currentwbcdate, 
baselinehepatitisb, baselinehepatitisc, interruptiontype, interruptionreason, 
interruptiondate, hivstatusatprepinitiation, indicationforprep, currentregimen, 
currentduration, currentpreptype, currentprepdistributionsetting, dateoflastpickup, 
currentsystolicbp, currentdiastolicbp, currentweight, currentheight, currenturinalysis, 
familyplanning, dateoffamilyplanning, currenturinalysisdate, currenthivstatus, 
dateofcurrenthivstatus, pregnancystatus, currentstatus, dateofcurrentstatus, 
period_start_date, period_end_date
FROM expanded_hts_prep.expanded_prep_weekly
